window.GLPI=window.GLPI||{};window.GLPI.RichText=window.GLPI.RichText||{};window.GLPI.RichText.ContentTemplatesParameters=class{constructor(e,t){this.editor=e;this.values=this.parseParameters(t)}register(){const e=this;this.editor.ui.registry.addAutocompleter("content_templates",{trigger:"{",minChars:0,fetch:function(t){return e.fetchItems(t)},onAction:function(t,r,n){e.insertTwigContent(t,r,n)}})}fetchItems(e){const t=this;return new Promise(r=>{const n=t.values.filter(r=>{e=e.trim();if(e.length===0){return true}const n=e.charAt(0);if(["{","%"].includes(n)&&n!==r.opening.charAt(1)){return false}let s=0;let i=null;tinymce.dom.TextSeeker(t.editor.dom,()=>false).backwards(t.editor.selection.getNode(),0,(e,t,r)=>{if(/\{%\s*endfor\s*%\}/.test(r)){s++}const n=r.match(/\{%\s*for\s+\w+\s+in\s+([\w.]+)\s*%\}/);if(n!==null){if(s==0){i=n[1];return t}s--}return-1});if(i!==null&&r.parent_key!==i){return false}else if(i===null&&r.parent_key!==undefined){return false}const o=e.replace(/^(\{|%)\s*/,"").toLowerCase();const a=r.key.toLowerCase().includes(o)||r.text.toLowerCase().includes(o);if(!a){return false}return true});r(n)})}parseParameters(e,t="",r=""){const n=[];const s=this;e.forEach(e=>{if(t.length>0){e.key=`${t}.${e.key}`}if(r.length>0){e.label=`${r} > ${e.label}`}switch(e.type){case"AttributeParameter":{let t=`{{ ${e.key}`;if(e.filter&&e.filter.length){t+=` | ${e.filter}`}t+=" }}";n.push({type:"autocompleteitem",opening:"{{",key:e.key,value:t,text:`${t} - ${e.label}`});break}case"ObjectParameter":{n.push(...s.parseParameters(e.properties,e.key,e.label));break}case"ArrayParameter":{const t=`{% for ${e.items_key} in ${e.key} %}`;n.push({type:"autocompleteitem",opening:"{%",key:e.key,value:t,text:`${t} - ${e.label}`});const r=s.parseParameters([e.content]);n.push(...r.map(t=>{t.opening="{{";t.parent_key=e.key;return t}));break}}});return n}insertTwigContent(e,t,r){this.editor.selection.setRng(t);if(r.indexOf("{% for ")==0){r=`${r}<br><br>{% endfor %}`}this.editor.insertContent(r);e.hide()}};